import React, { Component } from 'react';

class APIService extends Component {

  performRequest = (url, method, body) => {
    
    const headers = new Headers({
     'Content-Type': 'application/json'
    });

    if (this.state.token) {
      headers.append('Authorization', `Bearer ${this.state.token}`);
    }

    const options = {
      method,
      headers,
      body: body ? JSON.stringify(body) : null,
    };

    return fetch(`https://api.example.com/${url}`, options);
  }

  authenticate = async (username, password) => {
    try {
      const response = await this.performRequest('auth/login', 'POST', { username, password });
      
      if (response.ok) {
        const result = await response.json();
        this.setState({ token: result.token });
        return true;
      } else {
        throw new Error('Authentication failed.');
      }
    } catch (error) {
      console.error(error);
      return false;
    }
  }

  fetchUserProfile = async () => {
    try {
      const response = await this.performRequest('user/profile', 'GET');
      
      if (response.ok) {
        const profile = await response.json();
        return profile;
      } else {
        throw new Error('Fetching user profile failed.');
      }
    } catch (error) {
      console.error(error);
    }
  }

  updateData = async (data) => {
    try {
      const response = await this.performRequest('user/data', 'PUT', data);
      
      if (response.ok) {
        const result = await response.json();
        return result;
      } else {
        throw new Error('Data update failed.');
      }
    } catch (error) {
      console.error(error);
      return false;
    }
  }

}

export default APIService;